Blackjack CLI Based Game이번 과제는 Python을 활용해서 간단한 CLI Based Game을 만드는 것이다. 게임 실행결과 화면 Blackjack으로 게임을 종료하는 경우 뽑은 카드들의 수의 합이 21을 초과하여 상대편이 이기는 경우 코드 (Python)from random import shuffle import re import sys # player와 bank의 게임진행 상태 player_play = True bank_play = True # 뽑은 카드의 숫자 합이 21을 초과하는 경우의 palyer와 bank player_lose = False bank_lose = False turn = 0 # card_deck에 카드를 준비 def prepareCards(): for i in range(2, 11+1): for _ in range(4): card_deck.append(&#39;A&#39; if i == 11 else i) # card deck을 3회 shuffle def shuffleCardsTreeTimes(): return [shuffle(card_deck) for _ in range(3)] # card deck에 남아있는 카드가 10장 미만일 경우에 card deck을 reset하고 다시 shuffle한다. def resetCards(): # 카드를 다시 준비한다. prepareCards() # 카드를 다시 3회 섞는다. shuffleCards() # 사용자로부터 Y(y) or N(n)를 올바르게 입력받았는지 정규표현검사 def regexCheck(value): answer_check = re.compile(r&#39;^(?:Y|N)$&#39;, re.I) return answer_check.match(value) # 사용자로부터 한 번 더 shuffle할 것인지 물어보는 처리 def askMoreShuffle(): # 사용자로부터 한 번 더 shuffle을 할 것인지 묻기 while True: shuffle_more = input( &#39;✨✨✨✨✨✨✨Shuffle을 한 번 더 하길 원하십니까? (Y(y)/N(n))✨✨✨✨✨✨✨&#39;) # 사용자로부터 입력받을 Y/N를 정규표현식으로 검사 answer = regexCheck(shuffle_more) if answer: if answer.group() == &#39;Y&#39; or answer.group() == &#39;y&#39;: print(&quot;✨✨✨✨✨✨✨한 번 더 card deck의 shuffle을 진행합니다.✨✨✨✨✨✨✨&quot;) shuffle(card_deck) break else: print(&quot;✨✨✨✨✨✨✨추가적인 card deck의 shuffle을 진행하지 않습니다.✨✨✨✨✨✨✨&quot;) break else: print(&quot;🥲🥲🥲🥲🥲🥲🥲 입력을 확인후 다시 입력해주세요.🥲🥲🥲🥲🥲🥲🥲&quot;) # 뽑은 카드들의 숫자 합을 반환한다. def getSumOfCards(cards): sum_of_cards = 0 for idx, card in enumerate(cards): if card == &#39;A&#39;: # 우선 Ace 카드를 11로 치환해서 A 카드를 제외한 카드들의 숫자 합에 더해준다. sum_of_cards += 11 # 카드의 합이 21을 초과하는 경우, if sum_of_cards &gt; 21: # Ace카드를 1로 치환해서 더해준다. sum_of_cards -= 10 else: sum_of_cards += card return sum_of_cards # 뽑은 카드들의 숫자 합을 기준으로 결과를 판별한다. def checkSumOfCards(player, sum_of_cards): if sum_of_cards &gt; 21: print( &quot;😵‍💫😵‍💫😵‍💫😵‍💫😵‍💫&#123;0&#125;가 받은 카드들의 숫자 합이 21을 초과했습니다. &#123;0&#125;의 턴을 종료합니다.😵‍💫😵‍💫😵‍💫😵‍💫😵‍💫&quot;.format(player)) if player == &#39;뱅크&#39;: global player_lose bank_lose = True if player_lose: print(&quot;😮‍💨😮‍💨😮‍💨😮‍💨😮‍💨 사용자와 뱅크는 서로 비겼습니다. 😮‍💨😮‍💨😮‍💨😮‍💨😮‍💨&quot;) sys.exit(0) else: print(&quot;🎉🎉🎉🎉🎉🎉🎉 사용자가 이겼습니다. 🎉🎉🎉🎉🎉🎉🎉&quot;) sys.exit(0) else: player_lose = True elif sum_of_cards == 21: print( &quot;👍👍👍👍👍 &#123;0&#125;가 받은 카드들의 숫자 합이 21입니다. Blackjack으로 &#123;0&#125;가 승리하였습니다. 👍👍👍👍👍&quot;.format(player)) sys.exit(0) else: print(&quot;&#123;0&#125;가 받은 카드들의 숫자 합은 &#123;1&#125;입니다.&quot;.format(player, sum_of_cards)) # 딜러로부터 카드를 받는 처리 def receiveCard(player, cards): print(&quot;
&quot;) print(&quot;🌱🌱🌱🌱🌱🌱🌱 &lt;&lt; &#123;0&#125;의 &#123;1&#125;번째 카드 분배입니다. &gt;&gt;🌱🌱🌱🌱🌱🌱🌱&quot;.format( player, turn+2)) print(&quot;그 다음으로 &#123;&#125; 측 게임을 진행합니다. &quot;.format(player)) # 카드를 점검합니다. 카드 덱에 남아있는 카드가 10장 미만인 경우, # 카드덱의 상태를 재정비합니다. if len(card_deck) &lt; 10: resetCards() card = card_deck.pop() print(&#39;😃😃😃😃😃😃😃&#123;0:&gt;3&#125;는 &#123;1:&gt;2&#125; 카드를 받았습니다.😃😃😃😃😃😃😃&#39;.format(player, card)) cards.append(card) print(&quot;💡💡💡💡💡💡&#123;&#125;의 Card deck을 확인 =&gt; &#123;&#125;💡💡💡💡💡💡&quot;.format(player, cards)) # 카드를 뽑고, 카드의 합을 구하고, 카드의 합이 21을 초과하는지 검사하는 공통화 처리 def commonCardGameProcess(player, cards, sum_of_cards): # card deck으로부터 카드를 뽑습니다. receiveCard(player, cards) # 여지까지 뽑은 카드의 합을 구합니다. sum_of_cards = getSumOfCards(cards) # 여기서 cards의 숫자의 합이 21을 초과하는지 검사한다. checkSumOfCards(player, sum_of_cards) # player와 bank의 게임 def cardPlay(player, sum_of_cards, cards): global turn, player_play, bank_play print(&quot;
&quot;) print(&quot;🌱🌱🌱🌱🌱🌱🌱&lt; &#123;0&#125;의 &#123;1&#125;번째 카드 분배입니다. &gt;&gt;🌱🌱🌱🌱🌱🌱🌱&quot;.format( player, turn+2)) print(&quot;🔥🔥🔥🔥🔥🔥🔥 다음은 &#123;&#125;의 순서입니다. 🔥🔥🔥🔥🔥🔥🔥&quot;.format(player)) if player == &quot;뱅크&quot; and sum_of_cards &lt; 16: print(&quot;Dealer hit rule에 의해 카드의 합이 16을 넘지 않으므로, 카드를 뽑습니다.&quot;) # 카드를 뽑고, 뽑은 카드의 합을 구하고, 그 합이 21을 초과하지 않는지 검사 commonCardGameProcess(player, cards, sum_of_cards) # 사용자, 뱅크 모두 순회를 끝냈다면 turn 값을 1증가시켜준다. turn += 1 else: more_card = input( &quot;✊✊✊✊✊✊ 카드를 더 뽑으시겠습니까? (Y(y)/N(n)) ✊✊✊✊✊✊&quot;) result = regexCheck(more_card) if result.group() == &#39;Y&#39; or result.group() == &#39;y&#39;: # 카드를 뽑고, 뽑은 카드의 합을 구하고, 그 합이 21을 초과하지 않는지 검사 commonCardGameProcess(player, cards, sum_of_cards) # 사용자, 뱅크 모두 순회를 끝냈다면 turn 값을 1증가시켜준다. if player == &quot;뱅크&quot;: turn += 1 else: if player == &quot;사용자&quot;: player_play = False else: bank_play = False result_dict[player] = sum_of_cards if player == &quot;사용자&quot;: player_play = False if player == &quot;뱅크&quot;: bank_play = False # 게임의 순번에 따라 게임을 진행 # arg: player -&gt; 사용자, 뱅크 # arg: cards -&gt; 사용자(cards_for_bank), 뱅크(cards_for_bank) def rotateTurnOfGames(player, cards): global turn global player_play global bank_play # print(&#39;&#123;0&#125;의 카드 수의 총 합은 &#123;1&#125;입니다.&#39;.format(player, sum_of_cards)) sum_of_cards = getSumOfCards(cards) if turn &gt; 0: if (player == &quot;사용자&quot; and (player_lose != True and player_play != False)): cardPlay(player, sum_of_cards, cards) elif (player == &quot;뱅크&quot; and (bank_lose != True and bank_play != False)): cardPlay(player, sum_of_cards, cards) else: # 카드를 뽑고, 뽑은 카드의 합을 구하고, 그 합이 21을 초과하지 않는지 검사 commonCardGameProcess(player, cards, sum_of_cards) # 사용자, 뱅크 모두 순회를 끝냈다면 turn 값을 1증가시켜준다. if player == &quot;뱅크&quot;: turn += 1 # 게임 실행 card_deck = [] print(&quot;👨👨👨👨👨👨👨👨👨 카드를 준비합니다. 👨👨👨👨👨👨👨👨👨&quot;) prepareCards() # card_deck을 3회 섞는다. print(&quot;✨✨✨✨✨✨✨✨ 준비된 카드를 3회 섞습니다. ✨✨✨✨✨✨✨✨&quot;) shuffleCardsTreeTimes() # 카드를 한 번 더 섞을 것인지 사용자로부터 확인한다. askMoreShuffle() print(&quot;✨✨✨✨✨✨✨✨ 카드섞기를 완료하였습니다. ✨✨✨✨✨✨✨✨&quot;) # card shuffle이 완성된 후에는 tuple로 카드의 순서를 고정한다. card_deck = tuple(card_deck) print(&quot;
&quot;) print(&quot;💪💪💪💪💪💪💪💪 &lt; Blackjack Game Start &gt;&gt; 💪💪💪💪💪💪💪💪&quot;) print(&quot;게임이 시작됩니다. 사용자와 뱅크는 각 각 한 장의 카드를 받습니다.&quot;) # 뱅크와 user의 card를 보관할 리스트를 정의한다. cards_for_bank = list() cards_for_user = list() # 게임이 시작되면 bank와 user는 카드를 한 장씩 받게 된다. # 카드는 한쪽방향으로 꺼내기때문에 pop()으로 꺼내도록 한다. card_deck = list(card_deck) card_for_user = card_deck.pop() card_for_bank = card_deck.pop() cards_for_user.append(card_for_user) cards_for_bank.append(card_for_bank) # 받은 카드는 출력을 하도록 한다. print(&#39;&#123;0:&gt;3&#125;는 &#123;1:&gt;2&#125; 카드를 받았습니다.&#39;.format(&quot;사용자&quot;, card_for_user)) print(&#39;&#123;0:&gt;4&#125;는 &#123;1:&gt;2&#125; 카드를 받았습니다.&#39;.format(&quot;뱅크&quot;, card_for_bank)) sum_of_user_cards = 0 sum_of_bank_cards = 0 # cards_for_bank, cards_for_user player = &#123;&#39;사용자&#39;: cards_for_user, &#39;뱅크&#39;: cards_for_bank&#125; turn = 0 result_dict = &#123;&#125; while player_play or bank_play: for k, v in player.items(): result = rotateTurnOfGames(k, v) # print(result) print(&quot;
&quot;) print(&quot;✨✨✨✨✨✨✨✨✨✨✨✨✨✨&lt; Blackjack Game End &gt;&gt;✨✨✨✨✨✨✨✨✨✨✨✨✨✨&quot;) print(&quot;✨✨✨✨✨✨ 사용자가 뽑은 카드 수의 합은 &#123;사용자&#125;, 뱅크가 뽑은 카드 수의 합은 &#123;뱅크&#125;입니다. ✨✨✨✨✨✨&quot;.format( **result_dict)) game_result = [(k, v) for k, v in result_dict.items()] if result_dict[&#39;사용자&#39;] == result_dict[&#39;뱅크&#39;]: print(&quot;🎉🎉🎉🎉🎉🎉🎉 사용자와 뱅크는 비겼습니다. 🎉🎉🎉🎉🎉🎉🎉&quot;) else: sorted_result = sorted(game_result, key=lambda x: x[1], reverse=True) print(&quot;
&quot;) print(&quot;🎉🎉🎉🎉🎉🎉🎉🎉🎉🎉🎉🎉🎉게임의 승리자는 &#123;&#125;입니다.🎉🎉🎉🎉🎉🎉🎉🎉🎉🎉🎉🎉🎉&quot;.format( sorted_result[0][0]))

List / Dictionary Comprehension**Python을 더 Python스럽게 작성하기위해서 이 Comprehension을 이해하고 적절히 잘 사용해야한다. List Comprehension 리스트의 각 요소에 2를 곱해서 새로운 리스트 생성하기 (for-loop + list comprehension) numbers = [1, 2, 3, 4, 5] new_numbers = [] for i in numbers: new_numbers.append(i*2) print(new_numbers) # list comprehension을 사용해서 아래와 같이 간단하게 작성을 해줄 수 있다. new_numbers = [i*2 for i in numbers] 리스트의 요소중에 짝수인 수를 선별해서 해당 수에 제곱을 해서 새로운 리스트 생성하기 (for-loop + list comprehension) numbers = [1, 2, 3, 4, 5] new_numbers = [] # numbers 자료 중 짝수일때만 제곱하여 new_numbers에 추가한다. for i in numbers: if i % 2 == 0: new_numbers.append(i**2) # 조건문이 하나일때에는 for문 뒤에 위치하도록 한다. new_numbers = [i**2 for i in numbers if i % 2 == 0] 리스트의 요소중에 짝수는 제곱을, 홀수인 경우에는 세제곱을 해서 새로운 리스트를 생성하기 (list comprehension + Ternary operator) numbers = [1, 2, 3, 4, 5] new_numbers = [] # numbers 자료 중 짝수일때만 제곱하여 new_numbers에 추가한다. # 그렇지 않을 경우, 세제곱하여 new_numbers에 추가한다. # expression내에 조건을 달아줄때에는 삼항연산자로 조건처리를 해준다. new_numbers = [item**2 if item % 2 == 0 else item**3 for item in numbers] FizzBuzz (for-loop &amp; if-statement) # Fizzbuzz # 3의 배수 : Fizz, 5의 배수 : Buzz, 15의 배수 FizzBuzz numbers = [i for i in range(1, 100+1)] fizzbuzz_list = [] for i in numbers: if i % 15 == 0: fizzbuzz_list.append(&#39;FizzBuzz&#39;) elif i % 3 == 0: fizzbuzz_list.append(&#39;Fizz&#39;) elif i % 5 == 0: fizzbuzz_list.append(&#39;Buzz&#39;) else: fizzbuzz_list.append(i) # list comprehension으로 convert FizzBuzz (list comprehension + Ternary operator) # fizzbuzz with list comprehension numbers = [i for i in range(1, 100+1)] fizzbuzz_list = [&#39;fizzbuzz&#39; if i%15==0 else \ &#39;fizz&#39; if i%3==0 else \ &#39;buzz&#39; if i%5==0 else \ i for i in numbers] Leap year(list comprehension + for-loop, if-statement) # Leap year # Constraint: 1999~2101 year_list = [i for i in range(1999, 2101+1)] # 100으로 나눠지면 leap year가 아니다. # 4로 나눠지고, (100으로 나눠지지 않거나, 400으로 나눠지는 경우) is_leap_list = [] # 2000 = leap_year # 2100 = plain_year year = 2000 for year in year_list: if year%4==0 and (year%100!=0 or year%400==0): is_leap_list.append(&#39;leap_year&#39;) else: is_leap_list.append(year) Leap year(list comprehension with Ternary operator) # Leap year with list comprehension # Leap year: 4의 배수이면서, 100의 배수가 아니거나 400의 배수인 연도 # Constraint: 1999~2101 # Output: &#39;leap_year&#39; if i is leap_year else, i years = [i for i in range(1999, 2101+1)] is_leap_list = [&#39;leap_year&#39; if year%4==0 and (year%100!=0 or year%400==0) else year for year in years] # 2000 = leap_year # 2100 = plain_year print(is_leap_list) Functionalize the process of filtering leap year def is_leap(year): if year%4==0 and (year%100!=0 or year%400==0): return True return False is_leap_list = [&#39;leap_year&#39; if isi_leap(year) else year for year in years] print(is_leap_list) Dictionary Comprehensionfruits = &#123;&#39;a&#39;:&#39;apple&#39;, &#39;b&#39;:&#39;banana&#39;, &#39;c&#39;:&#39;coconut&#39;, &#39;d&#39;:&#39;durian&#39;&#125; over_six_fruits = &#123;&#125; # fruite value 중에 문자열 길이가 6보다 큰 경우에 새로운 dict에 담아서 새로운 dict 변수를 생성 for k, v in fruits.items(): if len(v) &gt; 6: over_six_fruits[k] = v 위의 코드를 Dictionary comprehension으로 작성 # Dictionary comprehension over_six_fruits = &#123;k:v for k,v in fruits.items() if len(v) &gt; 6&#125; Dictionary + for-loop with if-statement number_dict = &#123;&#39;pi&#39;:3.1415, &#39;e&#39;:2.71828, &#39;year&#39;:2021, &#39;month&#39;:2, &#39;day&#39;:1&#125; new_number_dict = &#123;&#125; for k,v in number_dict.items(): if v &lt; 3: new_number_dict[k] = v ** 2 print(new_number_dict) 위의 코드를 Dictionary comprehension으로 작성 number_dict = &#123;&#39;pi&#39;:3.1415, &#39;e&#39;:2.71828, &#39;year&#39;:2021, &#39;month&#39;:2, &#39;day&#39;:1&#125; # 아래와 같이 삼항연산자를 이용해서 조건처리를 해서 작성을 해 줄 수 있다. # 앞에서 key를 이미 정의해주었기 때문에 else구문에서는 key에 대한 정의를 생략하고 value에 대한 선언만 넣어준다. new_number_dict = &#123;k:v**2 if v &lt; 3 else v-1 for k,v in number_dict.items()&#125; 리스트의 각 문자열 요소의 길이를 구해서 새로운 리스트 변수 생성 (list comprehension + for-loop with map) a_word_list = [&#39;aback&#39;,&#39;abacus&#39;,&#39;abandon&#39;,&#39;abandoned&#39;,&#39;abandonment&#39;,&#39;abashed&#39;,&#39;abate&#39;,&#39;abbey&#39;,] 실행되는 순간에 나오는 것 a_word_len_list = [len(s) for s in a_word_list] # dict.get() # dict.setdefault() a_word_len_list = [] for len_ in map(len, a_word_list): a_word_len_list.append(len_) dict.get([key], [default value])와 dict.setdefault([key], [default value]) 활용 # len_dict = &#123;&#125; # 현재 len_dict에 len(apple)를 key값으로 가지는 값이 없으면 해당 key에 해당하는 변수를 0으로 초기화해서 넣어주고, 1을 누적해서 더해준다. # 현재 leln_dict에 len(apple) 5라는 키가 있다면 기존 값에 1을 더해서 누적해준다. len_dict[len(&#39;apple&#39;)] = len_dict.get(len(&#39;apple&#39;), 0) + 1 # key로 len(&#39;amp&#39;)의 값인 3으로 조회를 했을때 값이 없으면 default로 0을 선언해주고, 초기값에 1을 누적해서 더해준다. # 존재한다면 기존 값에 1을 더해서 누적을 해준다. len_dict[len(&#39;amp&#39;)] = len_dict.get(len(&#39;amp&#39;), 0) + 1 # 숙제) 위의 코드를 dictionary comprehension 으로 바꿔보기. len_dict = &#123;&#125; for word in a_word_list: len_dict[len(word)] = len_dict.get(len(word), 0) + 1 print(len_dict) &quot;&quot;&quot; sample output: &#123; 5: [&#39;apple&#39;, &#39;among&#39;] &#125; &quot;&quot;&quot; filtered_dict = &#123;&#125; filtered_dict.setdefault(len(&#39;among&#39;), []).append(&#39;among&#39;) filtered_dict.setdefault(len(&#39;among&#39;), []).append(&#39;among&#39;) filtered_dict.setdefault(len(&#39;among&#39;), []).append(&#39;amp&#39;) # 단어의 길이를 기준으로 단어들을 분류 for word in a_word_list: filtered_dict.setdefault(len(word), []).append(word) # 첫번째 알파벳 기준으로 단어들을 분류 for word in a_word_list: filtered_dict.setdefault(word[0], []).append(word) print(filtered_dict) File I/O 파일을 열고(open), 쓰고(write), 읽기(readline) 실습 # numbers.txt 파일 열고 쓰기 설정 및 문자열 encoding 방식을 &#39;utf-8&#39;으로 설정 f = open(&#39;./numbers.txt&#39;, &#39;w&#39;, encoding=&#39;utf-8&#39;) # 파일에 hello 쓰기 f.write(&#39;hello&#39;) # file 객체의 life-cycle 종료 f.close() # numbers.txt 파일 열고 읽기 설정 및 문자열 encoding 방식을 &#39;utf-8&#39;으로 설정 f = open(&#39;./numbers.txt&#39;, &#39;r&#39;, encoding=&#39;utf-8&#39;) # 파일의 한 줄을 읽고(readline) text 변수에 담기 text = f.readline() # 파일로부터 읽은 text 변수를 출력 print(text) # file 객체의 life-cycle 종료 f.close() 위에서는 open으로 파일을 연 후에 그 내용을 표시하고 close하였다. 아래 코드는 with을 활용한 코드 작성으로, 바로 옆에 수행 할 함수를 명시하고 alias로 f를 해주었다.with 구문을 사용하면 명시적 클로즈 처리가 불필요하게 되므로 close를 안하는 실수를 사전에 방지할 수 있다. with open(&#39;./numbers.txt&#39;, &#39;w&#39;, encoding=&#39;utf-8&#39;) as f: for _ in range(10): f.write(&#39;hello&#39;) with open(&#39;./numbers.txt&#39;, &#39;r&#39;, encoding=&#39;utf-8&#39;) as f: # 복수의 줄을 읽을때에는 .readlines() text_list = f.readlines() # 한 줄을 읽을때에는 .readline() for line in text_list: print(line.replace(&#39;
